import React from 'react';

const entries = [
  {
    role: 'Freelance Web Developer',
    company: 'Self-employed',
    duration: '2024 – Present',
    description: 'Built and deployed personal and academic web projects using HTML, CSS, JavaScript, and React.',
  },
  {
    role: 'IT Intern (Placeholder)',
    company: 'Company Name Here',
    duration: 'Month Year – Month Year',
    description: 'Placeholder experience entry. Update this with your actual internship or work experience.',
  },
];

const Experience = () => (
  <section
    id="Experience"
    className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
    style={{
      background: '#000',
      fontFamily: "'Orbitron', sans-serif",
    }}
  >
    <h1 className="font-bold text-4xl text-white text-center mb-12">
      Experience
    </h1>

    <div className="w-full max-w-2xl flex flex-col gap-5">
      {entries.map((e, i) => (
        <div
          key={i}
          className="rounded-xl p-6 shadow-md"
          style={{
            background: '#fff',
            borderLeft: '5px solid #0d6efd',
          }}
        >
          <h3 className="font-bold text-lg text-black">{e.role}</h3>

          <p className="italic text-sm text-gray-600 mt-1">
            {e.company}
          </p>

          <p className="text-xs text-gray-500 mt-1">
            {e.duration}
          </p>

          <p className="text-sm text-gray-700 mt-3">
            {e.description}
          </p>
        </div>
      ))}
    </div>
  </section>
);

export default Experience;
